#include <iostream>
using namespace std;

int cautare_binara(int v[], int st, int dr, int x) {
    while (st <= dr) {
        int mij = st + (dr - st) / 2;
        if (v[mij] == x) return mij;
        if (v[mij] < x) st = mij + 1;
        else dr = mij - 1;
    }
    return -1;
}

int main() {
    int n, x;
    if (!(cin >> n >> x)) return 0;
    int v[1000];
    for (int i = 0; i < n; i++) {
        cin >> v[i];
    }
    cout << cautare_binara(v, 0, n - 1, x) << endl;
    return 0;
}

