#include <iostream>
using namespace std;

int n, m;
int adj[101][101];
bool viz[101];

void dfs(int nod) {
    cout << nod << " ";
    viz[nod] = true;
    for (int i = 1; i <= n; i++) {
        if (adj[nod][i] == 1 && !viz[i]) {
            dfs(i);
        }
    }
}

int main() {
    if (!(cin >> n >> m)) return 0;
    for (int i = 0; i < m; i++) {
        int u, v;
        cin >> u >> v;
        adj[u][v] = 1;
        adj[v][u] = 1;
    }
    dfs(1);
    cout << endl;
